#[test]
fn would_break_non_json_nats_payload_handling() {
    // A NATS message with non-JSON payload should either be dropped or injected
    // with the _wm_bridged marker — currently it's injected as data=Null without
    // the marker, which means the agorabus→NATS path could re-forward it.
    // This test verifies the behavior is intentional.
    use wm_busbridge::forward::BridgedPayload;
    let non_json_bytes = b"not json at all";
    let parsed: serde_json::Value = serde_json::from_slice(non_json_bytes)
        .unwrap_or(serde_json::Value::Null);
    // The null value should not be detected as bridged (correct), but
    // it also will not carry the _wm_bridged marker when injected.
    // This is a potential gap: the bridge injects it as if it were local.
    assert!(!BridgedPayload::is_bridged(&parsed), "Null payload must not be detected as bridged");
    // TODO: verify the bridge drops non-JSON NATS messages rather than injecting them
}
